class Solution(object):
    def rearrangeBarcodes(self, barcodes):
        import heapq
        from collections import Counter
        count = Counter(barcodes)
        pq = [(-c, code) for code, c in count.items()]
        heapq.heapify(pq)
        result = []
        while pq:
            c1, code1 = heapq.heappop(pq)
            if result and result[-1] == code1:
                if not pq:
                    return []
                c2, code2 = heapq.heappop(pq)
                result.append(code2)
                if c2 < -1:
                    heapq.heappush(pq, (c2 + 1, code2))
                heapq.heappush(pq, (c1, code1))
            else:
                result.append(code1)
                if c1 < -1:
                    heapq.heappush(pq, (c1 + 1, code1))
        return result
